#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int xi[n], hi[n];
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &xi[i], &hi[i]);
        }
        for (int i = 0; i < n; i++) {
            int rightmost = -1;
            for (int j = i + 1; j < n; j++) {
                bool inSight = true;
                for (int k = i + 1; k < j; k++) {
                    if (hi[k] >= hi[i]) {
                        inSight = false;
                        break;
                    }
                }
                if (inSight && hi[j] < hi[i]) {
                    rightmost = j;
                }
            }
            printf("%d ", rightmost + 1);
        }
        printf("\n");
    }
    return 0;
}

