import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] xi = new int[n];
            int[] hi = new int[n];
            for (int i = 0; i < n; i++) {
                xi[i] = sc.nextInt();
                hi[i] = sc.nextInt();
            }
            for (int i = 0; i < n; i++) {
                int rightmost = -1;
                for (int j = i + 1; j < n; j++) {
                    boolean inSight = true;
                    for (int k = i + 1; k < j; k++) {
                        if (hi[k] >= hi[i]) {
                            inSight = false;
                            break;
                        }
                    }
                    if (inSight && hi[j] < hi[i]) {
                        rightmost = j;
                    }
                }
                System.out.print(rightmost + 1 + " ");
            }
            System.out.println();
        }
    }
}

